-- ── Anaplan ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Anaplan is an enterprise connected-planning platform used by large organizations for financial planning and analysis, supply chain planning, sales planning, and workforce planning on a single cloud data model.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$approx 2,700 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Anaplan 2026: Enterprise Connected Planning Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Anaplan is an enterprise connected planning platform for FP&amp;A, supply chain, and sales planning. See its history, features, pricing, and Thoma Bravo buyout.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Anaplan is an enterprise cloud software platform for connected business planning, spanning financial planning and analysis (FP&amp;A), supply chain planning, sales performance planning, and workforce planning within a single unified data model. It was founded in 2006 by Guy Haddleton, Sue Haddleton, and Michael Gould, originating in a converted barn in Yorkshire, England, before the company relocated its headquarters to San Francisco, California, as it scaled globally. Anaplan built its platform around a proprietary in-memory calculation engine known as Hyperblock, which allows large organizations to model complex, interconnected business scenarios across departments in real time rather than relying on disconnected spreadsheets. The company went public on the New York Stock Exchange under the ticker PLAN on October 12, 2018. In March 2022, private equity firm Thoma Bravo announced it would acquire Anaplan in an all-cash deal valued at approximately $10.7 billion (later renegotiated slightly downward to roughly $10.4 billion amid a dispute over compensation practices), taking the company private; the deal closed in mid-2022. As of its most recent public data, Anaplan employs roughly 2,700 people and serves more than 2,000 customers worldwide, including large enterprises across industries such as consumer goods, technology, retail, and financial services, with past public customer references including companies like Coca-Cola, Shell, and VMware. The platform today spans multiple planning domains: Finance modules support scenario planning, financial consolidation, and AI-driven analysis and reporting; Supply Chain modules cover demand planning, supply planning, and inventory optimization; Sales Planning modules use AI to align sales territories, quotas, and capacity to revenue opportunity; and Workforce Planning modules help align talent strategy and headcount budgets to business scenarios. Anaplan has increasingly layered AI-driven capabilities on top of its core planning engine, marketed under recent 'agentic enterprise' positioning to help organizations move faster from data to decisions. Anaplan does not publish standard pricing; sales are handled through a custom, quote-based enterprise process, with industry estimates suggesting typical annual contract values ranging from tens of thousands of dollars for smaller deployments up to seven figures annually for large, multi-module, multi-user enterprise rollouts, since cost is driven primarily by the number of users, the number of planning models, and which specific modules are licensed. As an enterprise-focused connected planning platform, Anaplan is typically compared to tools like Oracle EPM (formerly Hyperion), SAP Analytics Cloud, Workday Adaptive Planning, OneStream, and Jedox, and it is generally positioned toward large, complex organizations rather than small businesses, given its implementation cost and complexity.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b672821a-3f06-4f69-b3b2-0aae182ebd03';

