-- ── AndroidFileHost ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AndroidFileHost is a free file hosting service historically used by the Android modding community to distribute large ROM, kernel, and firmware files, though most of its original download infrastructure is no longer functional.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AndroidFileHost 2026: Status, History and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$AndroidFileHost was a free ROM and firmware file host for the Android modding community. See its history, current status, and community-run alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AndroidFileHost was a free file hosting website built specifically for the Android modding, custom ROM, and firmware community, closely associated with the XDA Developers forum ecosystem. For years it served as one of the primary places developers and enthusiasts uploaded large binary files -- custom ROMs, kernels, custom recoveries, GApps packages, and stock firmware images -- that were too large or too niche for general-purpose file hosts to support reliably and for free. The site was run independently by a long-time XDA community member rather than by a venture-backed company, and it built a reputation within the Android enthusiast community for being one of the few dependable, ad-light places to distribute large ROM-related files without hitting aggressive bandwidth caps or paywalls common on general consumer file lockers. Over the past several years, however, AndroidFileHost has become largely defunct: while the website itself remains online and its search/index pages are still browsable, most of the original download links no longer function, meaning a large volume of historical ROMs, kernels, recoveries, and mods that were hosted there are effectively inaccessible through the original site. In response, community members created independent archival efforts, most notably a project called AFHArchive, which crawled and preserved copies of files from AndroidFileHost before they disappeared, and some of the site's index now points to files preserved on the Internet Archive rather than serving files directly. There is no publicly documented founding company, funding history, or corporate ownership behind AndroidFileHost, consistent with its identity as a grassroots, community-operated service rather than a commercial SaaS business; there is also no indication of any paid tier ever having existed, as the service was always free to use for uploaders and downloaders alike. Because the platform's core download functionality has degraded significantly and it is not actively maintained in a meaningful way, it should be treated by users today primarily as a legacy resource: still worth checking or searching for historical files, but no longer a reliable primary destination for hosting new custom ROM or firmware releases, a role that has increasingly shifted to alternatives such as GitHub Releases, SourceForge, and dedicated archive mirrors within the XDA community.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '882377f1-49d8-4333-92e4-61ef8fcc52bd';

