-- ── AndroidIDE ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AndroidIDE is a free, open-source mobile app that lets developers write, build, and run real Gradle-based Android applications directly on an Android device, without needing a desktop computer.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AndroidIDE 2026: Build Android Apps On Your Phone$q$, seo_title),
  seo_meta_description = COALESCE($q$AndroidIDE lets you build real, Gradle-based Android apps directly on an Android device. Explore its features, open-source license, and current status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AndroidIDE is a free, open-source integrated development environment that runs directly on an Android device, allowing developers to write, build, and compile real Gradle-based Android applications entirely on their phone or tablet rather than on a desktop computer. It is a distinct project from Google's Android Studio, which is a desktop-only IDE; AndroidIDE instead targets the on-device, mobile-first development niche and is distributed by AndroidIDEOfficial, with source code hosted publicly on GitHub. AndroidIDE is licensed under the GNU General Public License version 3 (GPLv3) or later, meaning it is fully free and open source, with no cost to download or use. Under the hood, AndroidIDE provides a full Linux-like terminal environment on the device, built on top of the well-known Termux project, giving developers a genuine command-line experience for running build tools. It supports Gradle-based Android projects with minimal or no modification, meaning projects built for desktop Android Studio can, in many cases, be opened and compiled directly within AndroidIDE. The app bundles JDK 11 and JDK 17 for compiling Java and Kotlin code, provides API reference information for Android classes (including flags for deprecated, removed, or newly available APIs), and allows developers to export finished apps as Android App Bundles (AAB) suitable for publishing directly to the Google Play Store, all from an on-device workflow. This makes AndroidIDE particularly useful for developers in regions or situations where access to a laptop or desktop computer is limited or unavailable, for on-the-go bug fixes and small feature additions, or for hobbyists who want to learn Android development using only a phone. One important caveat for anyone evaluating AndroidIDE in 2026 is that the project is publicly documented as no longer actively maintained, meaning users should not expect new feature development, and may encounter compatibility issues with the newest Android Gradle Plugin or SDK versions going forward. As a free, open-source, community-built tool with no company, funding, or commercial pricing behind it, AndroidIDE occupies a unique niche compared to alternatives: it is the closest thing to a full native Android development environment that runs entirely on Android itself, distinct from cloud IDEs or remote-desktop-based mobile coding solutions.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '967241ce-ad2e-479e-8559-6bc5c95eaaea';

