-- ── Angaza ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Angaza is a pay-as-you-go (PAYG) financing and IoT metering software platform that helps off-grid solar and appliance companies offer affordable, embedded financing to customers in emerging markets across Africa and Asia.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$approx 150 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Angaza 2026: Pay-As-You-Go Solar Financing Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Angaza powers pay-as-you-go financing for off-grid solar and appliance companies in emerging markets. See its history, funding, features, and business model.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Angaza is a technology company that provides pay-as-you-go (PAYG) financing software for distributors of off-grid solar systems and other life-changing appliances, primarily serving last-mile markets across Africa and Asia. It was founded in 2010 by Stanford graduate Lesley Silverthorn Marincola, initially as a solar-light hardware company aimed at addressing energy poverty in rural, off-grid communities. In 2012, the company pivoted away from manufacturing its own solar-light hardware toward becoming a software and technology provider, building a PAYG metering and monitoring platform that other solar and appliance companies could use to finance their own products. The core of Angaza's technology is an embedded metering mechanism built into a distributor's hardware (such as a solar home system or solar water pump) that can remotely lock or unlock the device based on a customer's payment status, effectively turning otherwise unaffordable, high-upfront-cost products into small, manageable installment payments made over weeks or months via mobile money or cash. This embedded-finance model has allowed even very small, remote, last-mile distribution businesses to offer consumer financing they could not otherwise underwrite themselves, since Angaza's platform (rather than the distributor) manages payment tracking, credit risk data, and remote device control. Angaza is headquartered in San Francisco, California, with its technology deployed by distributor partners across more than 30 countries, predominantly in Sub-Saharan Africa (with early and continued strength in markets like Kenya and other East African countries) as well as parts of Asia. The company has raised meaningful venture funding over multiple rounds, including a $1.5 million seed round, a Series A round that combined to roughly $10.5 million, and a $13.5 million Series B round led by KawiSafi Ventures with participation from Total Carbon Neutrality Ventures and existing investors including Ajax Strategies, Emerson Collective, Rethink Impact, and Salesforce Ventures, reflecting strong interest from both climate-focused and mainstream venture investors in the off-grid energy access space. Angaza's platform and business model sit at the intersection of embedded finance, IoT-enabled hardware, and impact-oriented fintech, and the company is frequently referenced in energy-access and impact investing case studies (including by organizations like the Skoll Foundation and IMD business school) as a leading example of technology-enabled financial inclusion for underserved, cash-constrained populations. Pricing is not publicly listed, as Angaza sells its platform on a business-to-business basis to solar and appliance distribution companies rather than directly to consumers, with commercial terms customized to each distributor partner's scale and product line. Angaza is generally compared to other PAYG and off-grid solar technology enablers such as SolarisIndex platforms, Odyssey Energy Solutions, and PEG Africa's internal systems, though Angaza differentiates itself through its long operating history and its position as one of the earlier, more established software-only enablers in the space.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6005e3a2-aaff-4619-b719-e43cb61c6339';

